#[test]
fn test_tool_result_load_json() {
    let json = r####"
{
  "parts": [
    {
      "kind": "text",
      "value": "72°F and sunny"
    }
  ],
  "errorKind": "missing_tool",
  "errorMessage": "Tool 'get_weather' is not registered",
  "durationMs": 42
}
"####;
    let ctx = LoadContext::default();
    let result = ToolResult::from_json(json, &ctx);
    assert!(result.is_ok(), "Failed to load from JSON: {:?}", result.err());
    let instance = result.unwrap();
    assert!(instance.error_kind.is_some(), "Expected error_kind to be Some");
    assert_eq!(instance.error_kind.as_ref().unwrap(), &"missing_tool");
    assert!(instance.error_message.is_some(), "Expected error_message to be Some");
    assert_eq!(instance.error_message.as_ref().unwrap(), &"Tool 'get_weather' is not registered");
    assert!(instance.duration_ms.is_some(), "Expected duration_ms to be Some");
    assert_eq!(instance.duration_ms.as_ref().unwrap(), &42.0);
}

